// ============================================================================
// CONFIGURATION
// ============================================================================

const getNavItems = (role: string | null, sections: string[]) => {
  const allItems = [
    { href: "/", label: "Inicio", icon: Home, sectionId: "dashboard" },
    { href: "/comandas", label: "Comandas", icon: ClipboardList, sectionId: "orders" },
    { href: "/ambientes", label: "Ambientes", icon: View, sectionId: "tables" },
    { href: "/cartas", label: "Cartas", icon: BookOpen, sectionId: "menu" },
    { href: "/inventario", label: "Inventario", icon: Archive, sectionId: "inventory" },
    { href: "/pos-kds", label: "POS y KDS", icon: Monitor, sectionId: "pos" },
    { href: "/pos-kds/estaciones", label: "Estaciones", icon: Layers, sectionId: "pos" },
    { href: "/personal", label: "Personal", icon: Users, sectionId: "staff" },
    { href: "/personal/planificacion", label: "Planificación", icon: Calendar, sectionId: "staff" },
    { href: "/notificaciones", label: "Notificaciones", icon: Bell, sectionId: "notifications" },
    { href: "/reportes", label: "Reportes", icon: BarChart3, sectionId: "reports" },
    { href: "/reservas", label: "Reservas", icon: CalendarCheck, sectionId: "reservations" },
    { href: "/promociones", label: "Promociones", icon: BadgePercent, hidden: true, sectionId: "promotions" },
    { href: "/settings", label: "Configuración", icon: Settings, sectionId: "settings" },
  ];

  if (!role) return [];
  if (role === 'owner') return allItems;
  if (role === 'manager') return allItems; // Manager ve todo en el sidebar, pero restringiremos dentro de settings
  if (role === 'host') return allItems.filter(item => item.href === '/ambientes' || item.href === '/reservas');
  if (role === 'head_chef') return allItems.filter(item => item.href === '/cartas' || item.href === '/inventario');

  // waiter, cook, bartender, etc
  return allItems.filter(item => sections.includes(item.sectionId));
};

// ============================================================================
// COMPONENTS
// ============================================================================

export function SidebarNav() {
  const { state, isMobile, isTablet, setOpenMobile } = useSidebar()
  const isCollapsed = state === "collapsed"
  const pathname = usePathname()
  const router = useRouter()
  const { toast } = useToast()
  const { staff, role, sections } = useAuth()
  const [isDarkMode, setIsDarkMode] = React.useState(true)
  const { establishments, activeEstablishment, setActiveEstablishmentId, addEstablishment, removeEstablishment } = useEstablishments()
  const [establishmentToDelete, setEstablishmentToDelete] = React.useState<Establishment | null>(null)
  const [isCreateDialogOpen, setIsCreateDialogOpen] = React.useState(false)

  const handleNavigation = (href: string) => {
    // Dispatch instant loading event
    window.dispatchEvent(new CustomEvent('navigation-start'));

    // Close sidebar on mobile/tablet
    if (isMobile || isTablet) {
      setOpenMobile(false);
    }
  };

  const updateAbsenceRequestStatus = useMutation(api.staff.updateAbsenceRequestStatus)
  const absenceRequests = useQuery(api.staff.getAbsenceRequestsByEstablishment,
    activeEstablishment?.id ? { establishmentId: activeEstablishment.id as any } : "skip"
  )

  const pendingRequests = React.useMemo(() => {
    if (!absenceRequests) return []
    return absenceRequests.filter((req: any) => req.status === "pending")
  }, [absenceRequests])

  const pendingReservationsCount = 0 // Placeholder
  const totalNotifications = pendingRequests.length + pendingReservationsCount

  // Sync dark mode class
  React.useEffect(() => {
    const isDark = document.documentElement.classList.contains('dark')
    setIsDarkMode(isDark)
  }, [])

  React.useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark')
    else document.documentElement.classList.remove('dark')
  }, [isDarkMode])

  const handleSelectEstablishment = (id: string) => {
    setActiveEstablishmentId(id)
  }

  const handleAddEstablishment = () => {
    addEstablishment()
  }

  const handleDeleteEstablishment = () => {
    if (establishmentToDelete) {
      const willHaveRemaining = establishments.length > 1;
      removeEstablishment(establishmentToDelete.id)
      setEstablishmentToDelete(null)
      if (pathname.includes('/settings/profile')) {
        router.push(willHaveRemaining ? '/settings/profile?tab=establishment' : '/settings/profile')
      }
    }
  }

  const handleUpdateRequest = async (requestId: string, status: 'approved' | 'rejected') => {
    const statusEs = status === 'approved' ? 'Aprobada' : 'Rechazada'

    if (staff?._id) {
      await updateAbsenceRequestStatus({
        requestId: requestId as any,
        status,
        reviewed_by: staff._id as any
      })

      toast({
        title: `Solicitud ${statusEs}`,
        description: `La solicitud ha sido ${statusEs.toLowerCase()}.`
      })
    } else {
      toast({
        title: "Error",
        description: "No se pudo identificar tu usuario.",
        variant: "destructive"
      })
    }
  }

  return (
    <>
      <SidebarHeader padding="md">
        <NavEstablishments
          active={activeEstablishment}
          list={establishments}
          isCollapsed={isCollapsed}
          onSelect={handleSelectEstablishment}
          onAdd={handleAddEstablishment}
          onAssociate={() => setIsCreateDialogOpen(true)}
          onDelete={(est: any) => setEstablishmentToDelete(est)}
          role={role}
        />
      </SidebarHeader>

      <SidebarContent scrollbar>
        <NavMain items={getNavItems(role, sections)} pathname={pathname} onNavigate={handleNavigation} />
      </SidebarContent>

      <SidebarFooter padding="md">
        <NavUser
          user={{
            firstName: staff?.name,
            email: staff?.email || staff?.phone,
            avatar: staff?.photo_url || ''
          }}
          isCollapsed={isCollapsed}
          isDarkMode={isDarkMode}
          onDarkModeChange={setIsDarkMode}
          notifications={{
            total: totalNotifications,
            pendingRequests,
            onUpdateRequest: handleUpdateRequest
          }}
        />
      </SidebarFooter>

      {/* Delete Confirmation */}
      <AlertDialog open={!!establishmentToDelete} onOpenChange={(open) => !open && setEstablishmentToDelete(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>¿Eliminar establecimiento?</AlertDialogTitle>
            <AlertDialogDescription>
              Esta acción no se puede deshacer. Eliminarás <strong>{establishmentToDelete?.name}</strong> permanentemente.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel onClick={() => setEstablishmentToDelete(null)}>Cancelar</AlertDialogCancel>
            <AlertDialogAction onClick={handleDeleteEstablishment} variant="destructive">Sí, eliminar</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Create Establishment Dialog */}
      <CreateEstablishmentDialog
        open={isCreateDialogOpen}
        onOpenChange={setIsCreateDialogOpen}
      />
    </>
  )
}

// ----------------------------------------------------------------------------
// SUB-COMPONENTS
// ----------------------------------------------------------------------------

function NavEstablishments({ active, list, isCollapsed, onSelect, onAdd, onAssociate, onDelete, role }: any) {
  if (!active) return (
    role === 'owner' ? (
      <Button variant="outline" size="lg" width="full" onClick={onAssociate} startIcon={<PlusCircle />} responsive={true}>
        Crear Establecimiento
      </Button>
    ) : null
  )

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <SidebarMenuButton size="lg" variant="outline" className="h-14">
          <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-primary/10 overflow-hidden">
            <img
              src={active.id === 'camarai' || active.name === 'Camarai.es' ? "https://res.cloudinary.com/dxh2i2rjo/image/upload/v1769436934/camarailogo_lbsc9d.png" : active.image}
              alt={active.name}
              className={cn(
                "w-full h-full",
                active.id === 'camarai' || active.name === 'Camarai.es' ? "object-contain p-1.5" : "object-cover"
              )}
            />
          </div>
          <div className="flex flex-1 flex-col items-start overflow-hidden text-left leading-tight">
            <span className="truncate font-bold text-sm text-foreground">{active.name}</span>
            <span className="truncate text-[11px] text-muted-foreground">{active.type}</span>
          </div>
          {role === 'owner' && (
            <ChevronDown className="h-4 w-4 shrink-0 text-muted-foreground" />
          )}
        </SidebarMenuButton>
      </DropdownMenuTrigger>
      <DropdownMenuContent width="trigger" align="start" sideOffset={8}>
        <DropdownMenuGroup>
          {/* Active establishment first */}
          <DropdownMenuItem onSelect={() => onSelect(active.id)}>
            <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-primary/10 overflow-hidden">
              <img
                src={active.id === 'camarai' || active.name === 'Camarai.es' ? "https://res.cloudinary.com/dxh2i2rjo/image/upload/v1769436934/camarailogo_lbsc9d.png" : active.image}
                alt={active.name}
                className={cn(
                  "w-full h-full",
                  active.id === 'camarai' || active.name === 'Camarai.es' ? "object-contain p-1.5" : "object-cover"
                )}
              />
            </div>
            <div className="flex flex-1 flex-col items-start overflow-hidden text-left leading-tight">
              <span className="truncate font-bold text-sm text-foreground">{active.name}</span>
              <span className="truncate text-[10px] text-muted-foreground">{active.type}</span>
            </div>
            <Check className="h-4 w-4 ml-auto text-primary" />
          </DropdownMenuItem>

          {role === 'owner' && list.filter((est: any) => est.id !== active.id).length > 0 && (
            <DropdownMenuSeparator />
          )}

          {/* Other establishments */}
          {role === 'owner' && list
            .filter((est: any) => est.id !== active.id)
            .map((est: any) => (
            <DropdownMenuItem key={est.id} onSelect={() => onSelect(est.id)}>
              <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-primary/10 overflow-hidden">
                <img
                  src={est.id === 'camarai' || est.name === 'Camarai.es' ? "https://res.cloudinary.com/dxh2i2rjo/image/upload/v1769436934/camarailogo_lbsc9d.png" : est.image}
                  alt={est.name}
                  className={cn(
                    "w-full h-full",
                    est.id === 'camarai' || est.name === 'Camarai.es' ? "object-contain p-1.5" : "object-cover"
                  )}
                />
              </div>
              <div className="flex flex-1 flex-col items-start overflow-hidden text-left leading-tight">
                <span className="truncate font-bold text-sm text-foreground">{est.name}</span>
                <span className="truncate text-[10px] text-muted-foreground">{est.type}</span>
              </div>
            </DropdownMenuItem>
          ))}
        </DropdownMenuGroup>

        {role === 'owner' && (
          <>
            <DropdownMenuSeparator />
            <DropdownMenuItem onSelect={onAssociate}>
              <PlusCircle className="h-4 w-4" />
              <span>Asociar establecimiento</span>
            </DropdownMenuItem>
          </>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

function NavMain({ items, pathname, onNavigate }: any) {
  return (
    <SidebarGroup>
      <SidebarGroupContent>
        <SidebarMenu>
          {items.filter((item: any) => !item.hidden).map((item: any) => {
            const isActive = pathname === item.href
            return (
              <SidebarMenuItem key={item.label}>
                <SidebarMenuButton isActive={isActive} tooltip={item.label} asChild>
                  <Link href={item.href} onClick={() => onNavigate(item.href)}>
                    <item.icon />
                    <span>{item.label}</span>
                  </Link>
                </SidebarMenuButton>
              </SidebarMenuItem>
            )
          })}
        </SidebarMenu>
      </SidebarGroupContent>
    </SidebarGroup>
  )
}

function NavUser({ user, isCollapsed, isDarkMode, onDarkModeChange, notifications }: any) {
  const { toast } = useToast()
  const { logout } = useAuth()

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <SidebarMenuButton size="lg" variant="outline" className="h-14">
          <Avatar className="h-10 w-10 shrink-0 rounded-lg">
            <AvatarImage src={user.avatar} alt={user.firstName} className="object-cover" />
            <AvatarFallback className="rounded-lg bg-primary/10 text-primary font-bold">{user.firstName?.charAt(0)}</AvatarFallback>
          </Avatar>
          <div className="flex flex-1 flex-col items-start overflow-hidden text-left leading-tight">
            <span className="truncate font-bold text-sm text-foreground">{user.firstName}</span>
            <span className="truncate text-[11px] text-muted-foreground">{user.email}</span>
          </div>
          {notifications.total > 0 && <Badge variant="destructive" className="h-5 min-w-5 p-0 flex items-center justify-center text-[10px]">{notifications.total}</Badge>}
          <ChevronDown className="h-4 w-4 shrink-0 text-muted-foreground" />
        </SidebarMenuButton>
      </DropdownMenuTrigger>
      <DropdownMenuContent width="lg" side="top" align="start" margin="sm">
        <DropdownMenuItem asChild>
          <Link href="/settings/profile">
            <User />
            <span>Mi cuenta</span>
          </Link>
        </DropdownMenuItem>

        {/* Notifications Submenu */}
        <DropdownMenuSub>
          <DropdownMenuSubTrigger>
            <Bell />
            <span>Notificaciones</span>
            {notifications.total > 0 && (
              <Badge className="ml-1">
                {notifications.total}
              </Badge>
            )}
          </DropdownMenuSubTrigger>
          <DropdownMenuSubContent width="md">
            <DropdownMenuLabel>Solicitudes de ausencia</DropdownMenuLabel>
            <DropdownMenuGroup>
              {notifications.pendingRequests.length > 0 ? (
                notifications.pendingRequests.map((req: any) => {
                  return (
                    <DropdownMenuItem key={req.id}>
                       <Avatar>
                        <AvatarFallback>E</AvatarFallback>
                      </Avatar>
                      <div className="flex-1 flex flex-col min-w-0">
                        <span >Empleado</span>
                        <span >{req.type} - {format(parseISO(req.startDate), 'dd/MM/yy')}</span>
                      </div>
                      <div className="flex gap-1" onClick={(e) => e.stopPropagation()}>
                        <Button size="sm" variant="ghost-destructive" onClick={() => notifications.onUpdateRequest(req.id, 'rejected')} startIcon={<X  />} />
                        <Button size="sm" variant="ghost-success" onClick={() => notifications.onUpdateRequest(req.id, 'approved')} startIcon={<Check  />} />
                      </div>
                    </DropdownMenuItem>
                  )
                })
              ) : (
                <TextXS>Sin solicitudes pendientes</TextXS>
              )}
            </DropdownMenuGroup>
          </DropdownMenuSubContent>
        </DropdownMenuSub>

        <DropdownMenuItem asChild>
          <Link href="/privacy-policy" target="_blank" rel="noopener noreferrer">
            <Shield />
            Privacidad
          </Link>
        </DropdownMenuItem>

        <DropdownMenuItem onSelect={(e) => { e.preventDefault(); onDarkModeChange(!isDarkMode); }}>
          {isDarkMode ? <Moon /> : <Sun />}
          <span>{isDarkMode ? 'Modo noche' : 'Modo claro'}</span>
          <Switch checked={isDarkMode} onCheckedChange={onDarkModeChange} />
        </DropdownMenuItem>

        <DropdownMenuItem onSelect={() => {
          toast({ title: 'Saliendo...', description: 'Hasta pronto.' });
          logout();
        }}>
          <LogOut />
          Cerrar sesión
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  )
}
