'use client';

import * as React from 'react';
import { SidebarProvider, Sidebar, SidebarInset } from '@/components/ui/sidebar';
import { SidebarNav } from '@/components/layout/sidebar-nav';
import { EstablishmentProvider } from '../../hooks/EstablishmentContext';
import { AuthProvider, useAuth } from '../../hooks/useAuth';
import { Toaster } from '@/components/ui/toaster';
import { useIsMobile } from '@/hooks/use-mobile';
import { cn } from '@/lib/utils';
import { usePathname } from 'next/navigation';
import Loading from '../../app/loading';
import { MobileHeader } from '@/components/layout/mobile-header';
import { useScrollbarCompensation } from '@/hooks/use-scrollbar-compensation';
import { ConvexProvider, ConvexReactClient, useMutation } from "convex/react";
import { api } from "../../../convex/_generated/api";

// Singleton Convex client - created once outside any component
let convexClient: ConvexReactClient | null = null;

function getConvexClient() {
  if (convexClient) return convexClient;
  const url = process.env.NEXT_PUBLIC_CONVEX_URL || process.env.CONVEX_SELF_HOSTED_URL;
  if (!url) return null;
  try {
    convexClient = new ConvexReactClient(url);
    return convexClient;
  } catch (error) {
    console.error('Error inicializando Convex:', error);
    return null;
  }
}

// Tracker global para la última acción del usuario
let lastUserAction = "Ninguna acción registrada";

if (typeof window !== "undefined") {
  window.addEventListener("click", (e) => {
    const target = e.target as HTMLElement;
    const text = target.innerText || target.getAttribute("aria-label") || target.tagName;
    const id = target.id ? `#${target.id}` : "";
    const className = target.className && typeof target.className === 'string' ? `.${target.className.split(' ')[0]}` : "";
    lastUserAction = `Click en <${target.tagName.toLowerCase()}${id}${className}> ${text ? `"${text.substring(0, 30)}"` : ''}`;
  }, true);
}

class ErrorBoundary extends React.Component<{
  children: React.ReactNode;
  logError: any;
}, { hasError: boolean }> {
  constructor(props: any) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError() {
    return { hasError: true };
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    let authId = undefined;
    try {
      const session = localStorage.getItem('whatauth_session');
      if (session) {
        const parsed = JSON.parse(session);
        if (parsed?.user?.id) authId = parsed.user.id;
      }
    } catch {}

    let estId = undefined;
    try {
      const activeEstStr = localStorage.getItem('activeEstablishmentId');
      if (activeEstStr) estId = JSON.parse(activeEstStr);
    } catch {}

    this.props.logError({
      level: "critical",
      message: error.message || "React Rendering Error",
      stack: error.stack,
      url: window.location.href,
      authId: authId,
      establishmentId: estId,
      userAgent: navigator.userAgent,
      componentStack: errorInfo.componentStack,
      lastAction: lastUserAction,
    }).catch(() => {});
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="p-4 m-4 bg-red-50 text-red-900 border border-red-200 rounded-md">
          <h2 className="text-lg font-bold mb-2">Algo ha fallado en la interfaz.</h2>
          <p className="text-sm">El error ha sido registrado y reportado automáticamente. Por favor, recarga la página.</p>
          <button onClick={() => window.location.reload()} className="mt-4 px-4 py-2 bg-red-600 text-white rounded-md text-sm">
            Recargar página
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}

function GlobalErrorHandler({ children }: { children: React.ReactNode }) {
  const logError = useMutation(api.audit.logFrontendError);

  React.useEffect(() => {
    // Lista de errores comunes del navegador/red que no son errores de la aplicación
    const IGNORED_ERRORS = [
      "Network Error",
      "Failed to fetch",
      "Load failed",
      "ResizeObserver loop limit exceeded",
      "ResizeObserver loop completed with undelivered notifications",
      "Script error"
    ];

    const isIgnoredError = (msg: string) => {
      if (!msg) return false;
      return IGNORED_ERRORS.some(ignored => msg.includes(ignored));
    };

    // Escuchar errores no controlados y promesas rechazadas
    const handleWindowError = (event: ErrorEvent) => {
      const errorMsg = event.message || "Unknown Error";
      if (isIgnoredError(errorMsg)) return;

      let authId = undefined;
      try {
        const session = localStorage.getItem('whatauth_session');
        if (session) {
          const parsed = JSON.parse(session);
          if (parsed?.user?.id) authId = parsed.user.id;
        }
      } catch {}

      let estId = undefined;
      try {
        const activeEstStr = localStorage.getItem('activeEstablishmentId');
        if (activeEstStr) estId = JSON.parse(activeEstStr);
      } catch {}

      // Extraer línea y fichero (si event.filename está disponible)
      const locationInfo = event.filename ? `\n\nOrigen del error: ${event.filename} (Línea: ${event.lineno}, Columna: ${event.colno})` : '';

      logError({
        level: "critical",
        message: (event.message || "Unknown Error") + locationInfo,
        stack: event.error?.stack,
        url: window.location.href,
        authId: authId,
        establishmentId: estId,
        userAgent: navigator.userAgent,
        lastAction: lastUserAction,
      }).catch(() => {});
    };

    const handleUnhandledRejection = (event: PromiseRejectionEvent) => {
      const errorMsg = event.reason?.message || String(event.reason);
      if (isIgnoredError(errorMsg)) return;

      let authId = undefined;
      try {
        const session = localStorage.getItem('whatauth_session');
        if (session) {
          const parsed = JSON.parse(session);
          if (parsed?.user?.id) authId = parsed.user.id;
        }
      } catch {}

      let estId = undefined;
      try {
        const activeEstStr = localStorage.getItem('activeEstablishmentId');
        if (activeEstStr) estId = JSON.parse(activeEstStr);
      } catch {}

      logError({
        level: "critical", // unhandled promise rejection
        message: event.reason?.message || String(event.reason),
        stack: event.reason?.stack,
        url: window.location.href,
        authId: authId,
        establishmentId: estId,
        userAgent: navigator.userAgent,
        lastAction: lastUserAction,
      }).catch(() => {});
    };

    window.addEventListener("error", handleWindowError);
    window.addEventListener("unhandledrejection", handleUnhandledRejection);

    const originalConsoleError = console.error;
    const originalConsoleWarn = console.warn;

    console.error = (...args: any[]) => {
      originalConsoleError.apply(console, args);
      
      let authId = undefined;
      try {
        const session = localStorage.getItem('whatauth_session');
        if (session) {
          const parsed = JSON.parse(session);
          if (parsed?.user?.id) authId = parsed.user.id;
        }
      } catch {}

      let estId = undefined;
      try {
        const activeEstStr = localStorage.getItem('activeEstablishmentId');
        if (activeEstStr) estId = JSON.parse(activeEstStr);
      } catch {}

      const message = args.map(arg => typeof arg === 'object' && arg instanceof Error ? arg.message : typeof arg === 'object' ? JSON.stringify(arg) : String(arg)).join(' ');
      if (isIgnoredError(message)) return;
      const stack = args.find(arg => arg instanceof Error)?.stack;

      logError({
        level: "critical",
        message: message,
        stack: stack,
        url: window.location.href,
        authId: authId,
        establishmentId: estId,
        userAgent: navigator.userAgent,
        lastAction: lastUserAction,
      }).catch(() => {});
    };

    console.warn = (...args: any[]) => {
      originalConsoleWarn.apply(console, args);
      
      let authId = undefined;
      try {
        const session = localStorage.getItem('whatauth_session');
        if (session) {
          const parsed = JSON.parse(session);
          if (parsed?.user?.id) authId = parsed.user.id;
        }
      } catch {}

      let estId = undefined;
      try {
        const activeEstStr = localStorage.getItem('activeEstablishmentId');
        if (activeEstStr) estId = JSON.parse(activeEstStr);
      } catch {}

      const message = args.map(arg => typeof arg === 'object' && arg instanceof Error ? arg.message : typeof arg === 'object' ? JSON.stringify(arg) : String(arg)).join(' ');
      if (isIgnoredError(message)) return;
      const stack = args.find(arg => arg instanceof Error)?.stack;

      logError({
        level: "moderate",
        message: message,
        stack: stack,
        url: window.location.href,
        authId: authId,
        establishmentId: estId,
        userAgent: navigator.userAgent,
        lastAction: lastUserAction,
      }).catch(() => {});
    };

    return () => {
      window.removeEventListener("error", handleWindowError);
      window.removeEventListener("unhandledrejection", handleUnhandledRejection);
      console.error = originalConsoleError;
      console.warn = originalConsoleWarn;
    };
  }, [logError]);

  return <ErrorBoundary logError={logError}>{children}</ErrorBoundary>;
}

function MainContent({ children }: { children: React.ReactNode }) {
  const { isMobile, isTablet } = useIsMobile();
  const pathname = usePathname();
  const [isNavigating, setIsNavigating] = React.useState(false);
  const [isMounted, setIsMounted] = React.useState(false);

  React.useEffect(() => {
    setIsMounted(true);
    const handleStart = () => setIsNavigating(true);
    window.addEventListener('navigation-start', handleStart);
    return () => window.removeEventListener('navigation-start', handleStart);
  }, []);

  React.useEffect(() => {
    if (!isMounted) return;
    setIsNavigating(true);
    const timer = setTimeout(() => setIsNavigating(false), 500);
    return () => clearTimeout(timer);
  }, [pathname, isMounted]);

  if (!isMounted) {
    return (
      <SidebarInset className="!pl-0">
        <div className="flex-1 flex flex-col">{children}</div>
      </SidebarInset>
    );
  }

  const paddingClass = (isMobile || isTablet) ? 'pt-[calc(5rem+env(safe-area-inset-top))] pl-0 pb-[env(safe-area-inset-bottom)]' : '';

  return (
    <SidebarInset className={cn("transition-[padding] !pl-0", paddingClass)}>
      {isNavigating && <Loading />}
      <div className={cn(
        "flex-1 flex flex-col transition-opacity duration-300",
        isNavigating ? "opacity-0" : "opacity-100"
      )}>
        {children}
      </div>
    </SidebarInset>
  );
}

function AppShell({ children }: { children: React.ReactNode }) {
  useScrollbarCompensation();
  const { isAuthenticated } = useAuth();
  const pathname = usePathname();

  // If not authenticated and not on login page, we could redirect, 
  // but it's better to handle it by showing only login page content
  // or using a layout-level check.
  
  const isLoginPage = pathname === '/login';

  if (!isAuthenticated && !isLoginPage) {
    // We can't use redirect() here as it's a client component and we want to avoid infinite loops
    // or flickering. The useAuth hook handles initial loading.
    if (typeof window !== 'undefined') {
       window.location.href = '/login';
    }
    return null;
  }

  if (isLoginPage) {
    return (
      <>
        {children}
        <Toaster />
      </>
    );
  }

  return (
    <EstablishmentProvider>
      <SidebarProvider>
        <MobileHeader />
        <Sidebar variant="sidebar" collapsible="icon">
          <SidebarNav />
        </Sidebar>
        <MainContent>{children}</MainContent>
      </SidebarProvider>
      <Toaster />
    </EstablishmentProvider>
  );
}

export function ClientLayout({ children }: { children: React.ReactNode }) {
  const client = getConvexClient();

  const content = (
    <AuthProvider>
      <GlobalErrorHandler>
        <AppShell>{children}</AppShell>
      </GlobalErrorHandler>
    </AuthProvider>
  );

  if (client) {
    return (
      <ConvexProvider client={client}>
        {content}
      </ConvexProvider>
    );
  }

  return content;
}
